using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    private readonly HttpClient _httpClient;

    public ApiFetchTool(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient("ExternalApi");
    }

    [McpServerTool(Name = "fetch_external_data"), Description("Fetches data from an external API endpoint.")]
    public async Task<string> FetchExternalDataAsync(
        [Description("The relative API path to fetch (e.g. \"users/1\").")] string path,
        CancellationToken cancellationToken = default)
    {
        var response = await _httpClient.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public static class SummarizePrompt
{
    [McpServerPrompt(Name = "summarize"), Description("Creates a prompt that asks for a concise summary of the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum sentence count for the summary.")] int? maxSentences = null)
    {
        var constraint = maxSentences.HasValue
            ? $" Use no more than {maxSentences.Value} sentence(s)."
            : string.Empty;

        return
        [
            new()
            {
                Role = Role.User,
                Content = new TextContentBlock
                {
                    Text = $"Please provide a concise summary of the following text.{constraint}\n\n{text}"
                }
            }
        ];
    }
}

