[McpServerPromptType]
public static class SummarizePrompt
{
    [McpServerPrompt(Name = "summarize"), Description("Creates a prompt that asks for a concise summary of the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional maximum sentence count for the summary.")] int? maxSentences = null)
    {
        var constraint = maxSentences.HasValue
            ? $" Use no more than {maxSentences.Value} sentence(s)."
            : string.Empty;

        return
        [
            new()
            {
                Role = Role.User,
                Content = new TextContentBlock
                {
                    Text = $"Please provide a concise summary of the following text.{constraint}\n\n{text}"
                }
            }
        ];
    }
}

