using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    private readonly HttpClient _httpClient;

    public ApiFetchTool(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient("ExternalApi");
    }

    [McpServerTool(Name = "fetch_external_data"), Description("Fetches data from an external API endpoint.")]
    public async Task<string> FetchExternalDataAsync(
        [Description("The relative API path to fetch (e.g. \"users/1\").")] string path,
        CancellationToken cancellationToken = default)
    {
        var response = await _httpClient.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

